import socket
import json

class GameServer:
    def __init__(self):
        self.players = {}
        self.game_state = {}

    def handle_udp_query(self, data, addr):
        if data == b'status':
            response = {
                'players': list(self.players.keys()),
                'game_state': self.game_state
            }
            return json.dumps(response).encode()
        else:
            return None

    def start(self):
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.bind(('', 1234))
        while True:
            data, addr = sock.recvfrom(1024)
            response = self.handle_udp_query(data, addr)
            if response is not None:
                sock.sendto(response, addr)